  ('bookkeeper-moex-01312', 'bookkeeper', 'bookkeeper-moex-104-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '張君於民國102年12月31日自臺中市地方稅務局離職，現在是民國104年11月21日，請問下列敘述何者 正確？ 離職未滿三年，不得執行記帳士職務 離職未滿二年，不得執行記帳士職務 民國102年12月31日離職後，即可在臺中市區域外執行記帳士職務 曾任稅務機關稅務職系人員者，終身不得執行記帳士職務', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "905d3fabe5f9", "answer_pdf_sha1": "03ba1485918e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01313', 'bookkeeper', 'bookkeeper-moex-104-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列那一項業務非屬記帳士之執行業務範圍？ 受理稅務諮詢事項 受委任辦理各項稅捐稽徵案件之申報及申請事項 受委任辦理各項稅捐稽徵案件之查核簽證申報 受委任辦理營業、變更、註銷、停業、復業或其他登記事項', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "905d3fabe5f9", "answer_pdf_sha1": "03ba1485918e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01314', 'bookkeeper', 'bookkeeper-moex-104-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '根據記帳士法第16條規定，記帳士執行業務，應設置簿冊，下列那一項非屬於該條文所列示之載明事項？ 受委任記帳士之姓名及證書字號  委任案件之類別及內容 委任酬勞金額    委任人之姓名或名稱及地址', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "905d3fabe5f9", "answer_pdf_sha1": "03ba1485918e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01315', 'bookkeeper', 'bookkeeper-moex-104-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '李記帳士於11月5日收到記帳士懲戒委員會之懲戒處分通知書，請問該通知書應通知李記帳士於何日之前 提出答辯？ 11月15日  11月20日  11月25日  12月5日 依記帳士法第 條規定，記帳士受停止執行業務處分累計滿多少年者應予除名？', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "905d3fabe5f9", "answer_pdf_sha1": "03ba1485918e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
