  ('bookkeeper-moex-01326', 'bookkeeper', 'bookkeeper-moex-104-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '台逢公司以一運輸設備交換德力公司機器設備一部，德力公司之機器設備公允價值$400,000，台逢公司的運輸 設備成本$600,000，累計折舊$300,000，沒有公允價值，依交易條件，台逢另外支付現金$50,000 給德力，請 問台逢公司換入之機器設備入帳金額為何？ $400,000  $300,000  $600,000  $350,000', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "905d3fabe5f9", "answer_pdf_sha1": "03ba1485918e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
