  ('bookkeeper-moex-01328', 'bookkeeper', 'bookkeeper-moex-104-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依商業會計法對於費用及損失之規定，下列敘述何者正確？ 商業有支付員工退休金之義務者，應於支付時認列為當期費用 具有負債性質之特別股，其股利應認列為費用 商業對業主分配之盈餘，應作為當期費用 費用之抵銷額可列為收入', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "905d3fabe5f9", "answer_pdf_sha1": "03ba1485918e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1201", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL);
